import java.time.LocalDateTime
import java.time.format.DateTimeFormatter

val summaryCls = searchEmails("family reunion").map { emails =>
  // Combine subjects and bodies of relevant emails
  val contents = emails.map(e => s"Subject: ${e.subject}\n${e.body}").mkString("\n\n")
  // Extract start datetime
  val start = prompt(
    "Extract the start date and time for the family reunion in format YYYY-MM-DD HH:MM from the following emails. " +
    "Only reply with the datetime or 'No datetime found'. Emails:\n" + contents
  )
  if (start == "No datetime found") {
    "No start datetime found in the emails. Event not created."
  } else {
    // Extract location
    val locRaw = prompt(
      "Extract the location for the family reunion from the following emails. " +
      "Only reply with the location or 'No location found'. Emails:\n" + contents
    )
    // Summarize details for description
    val desc = prompt(
      "Summarize in one or two sentences the details for the family reunion event description. Emails:\n" + contents
    )
    // Parse and compute end time (+4 hours)
    val fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm")
    val ldt = LocalDateTime.parse(start, fmt)
    val endLdt = ldt.plusHours(4)
    val end = endLdt.format(fmt)
    // Prepare location option
    val locOpt = if (locRaw == "No location found") None else Some(locRaw)
    // Create the calendar event
    val event = createCalendarEvent(
      "Family Reunion",
      start,
      end,
      description = desc,
      participants = None,
      location = locOpt
    )
    // Build summary message
    val locStr = locOpt.map(l => s" at $l").getOrElse("")
    s"Created event '${event.title}' on ${event.startTime} to ${event.endTime}${locStr}."
  }
}
// Display the result securely to the user
displaySecurely(summaryCls)

